promptInstructions:
Analyze the provided files and produce a {{.stateKeys.depth}} analysis.

{{.depthInstructions}}

{{.formatInstructions}}

commands.handler:
function (args) {
  var depth = state.get(stateKeys.depth);
  var format = state.get(stateKeys.format);
  var i = 0;
  while (i < args.length) {
    if (args[i] === '-depth' && i + 1 < args.length) {
      var validDepths = ['quick', 'standard', 'deep'];
      if (validDepths.indexOf(args[i + 1]) !== -1) {
        depth = args[i + 1];
        state.set(stateKeys.depth, depth);
      } else {
        output.print('Invalid depth: ' + args[i + 1] + '. Use: ' + validDepths.join(', '));
        return;
      }
      i += 2;
    } else if (args[i] === '-format' && i + 1 < args.length) {
      var validFormats = ['prose', 'structured', 'json'];
      if (validFormats.indexOf(args[i + 1]) !== -1) {
        format = args[i + 1];
        state.set(stateKeys.format, format);
      } else {
        output.print('Invalid format: ' + args[i + 1] + '. Use: ' + validFormats.join(', '));
        return;
      }
      i += 2;
    } else {
      i++;
    }
  }
  output.print('Analysis settings:');
  output.print('  Depth:  ' + depth);
  output.print('  Format: ' + format);
  output.print('');
  output.print('Use "copy" to generate the analysis prompt.');
}

function (args) {
  var valid = ['quick', 'standard', 'deep'];
  if (!args || args.length === 0) {
    output.print('Current depth: ' + state.get(stateKeys.depth));
    output.print('Available: ' + valid.join(', '));
    return;
  }
  if (valid.indexOf(args[0]) === -1) {
    output.print('Invalid depth: ' + args[0] + '. Use: ' + valid.join(', '));
    return;
  }
  state.set(stateKeys.depth, args[0]);
  output.print('Depth set to: ' + args[0]);
}

function (args) {
  var valid = ['prose', 'structured', 'json'];
  if (!args || args.length === 0) {
    output.print('Current format: ' + state.get(stateKeys.format));
    output.print('Available: ' + valid.join(', '));
    return;
  }
  if (valid.indexOf(args[0]) === -1) {
    output.print('Invalid format: ' + args[0] + '. Use: ' + valid.join(', '));
    return;
  }
  state.set(stateKeys.format, args[0]);
  output.print('Format set to: ' + args[0]);
}
